return {
  draw: function(ctx, W, H, t, dt) {
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    ctx.strokeStyle = '#374151';
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.moveTo(50, H / 2);
    ctx.lineTo(W - 50, H / 2);
    ctx.stroke();

    var numPoints = 5;
    var spacing = (W - 100) / (numPoints - 1);
    for (var i = 0; i < numPoints; i++) {
      var val = i + 1;
      var x = 50 + i * spacing;
      var y = H / 2;

      var activeIdx = Math.floor(t * 0.03) % numPoints;
      var isActive = (i === activeIdx);
      var r = isActive ? 16 + Math.sin(t * 0.15) * 3 : 10;

      ctx.fillStyle = isActive ? '#EC4899' : '#4B5563';
      ctx.beginPath();
      ctx.arc(x, y, r, 0, Math.PI * 2);
      ctx.fill();

      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillStyle = isActive ? '#F3F4F6' : '#9CA3AF';
      ctx.textAlign = 'center';
      ctx.fillText(val.toString(), x, y - 25);

      if (isActive && i > 0) {
        ctx.font = '12px -apple-system, sans-serif';
        ctx.fillStyle = '#10B981';
        ctx.fillText('+1', x - spacing / 2, y - 10);
      }
    }
  }
};
